accessControlFunction:
function(doc, oldDoc, meta) {
  if (doc._deleted) {
    if (oldDoc && oldDoc.schoolId) channel('sch::' + oldDoc.schoolId);
    return;
  }
  if (!doc.schoolId) throw({ forbidden: 'schoolId requis' });
  channel('sch::' + doc.schoolId);
  if (doc.groupId) channel('grp::' + doc.groupId);
}
